// ============================================================================
// Main CLI
// ============================================================================

const mainCommand = Command.make("mdtldr").pipe(
  Command.withDescription("Token-efficient markdown analysis tool for LLMs"),
  Command.withSubcommands([
    parseCommand,
    treeCommand,
    structureCommand,
    indexCommand,
    linksCommand,
    backlinksCommand,
